codontable = """UUU F      CUU L      AUU I      GUU V
UUC F      CUC L      AUC I      GUC V
UUA L      CUA L      AUA I      GUA V
UUG L      CUG L      AUG M      GUG V
UCU S      CCU P      ACU T      GCU A
UCC S      CCC P      ACC T      GCC A
UCA S      CCA P      ACA T      GCA A
UCG S      CCG P      ACG T      GCG A
UAU Y      CAU H      AAU N      GAU D
UAC Y      CAC H      AAC N      GAC D
UAA Stop   CAA Q      AAA K      GAA E
UAG Stop   CAG Q      AAG K      GAG E
UGU C      CGU R      AGU S      GGU G
UGC C      CGC R      AGC S      GGC G
UGA Stop   CGA R      AGA R      GGA G
UGG W      CGG R      AGG R      GGG G"""

codondict = {}
aatemp = ""
codestemp = ""
for line in codontable.splitlines():
    for characters in line.split():
        if len(characters) == 1:
            aatemp = characters
        elif len(characters) == 4:
            aatemp = characters
        else:
            codestemp = characters
        if not aatemp:
            continue
        else:
            codondict[codestemp] = aatemp

s = ""

if len(s)%3 == 1:
    s = s[:-1]
elif len(s)%3 == 2:
    s = s[:-2]

translation = ""
for x in range(0, len(s), 3):
    if codondict[s[x:x+3]] == "Stop":
        break
    translation = translation + codondict[s[x:x+3]]
    print(len(s))
    print(x)
    print(s[x:x+3], codondict[s[x:x+3]])

print(translation)

h = open("rosalind8ans.txt", "w+")
h.write(translation)
h.close()
